INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '0680567c-c6bf-4a99-a350-52b213c593e7',
  '00000000-0000-0000-0000-000000000001',
  $escape$linux_kernel — Mastering Kconfig/Makefile for Module Development$escape$,
  $escape$The linux_kernel configuration system relies on Kconfig and Makefile to determine which modules to build. Kconfig files contain conditional statements that specify module dependencies. When a Kconfig file is updated, the Makefile is automatically regenerated. To build a specific module, navigate to its directory and run `make`. The Makefile will automatically include the necessary configuration files. To add a new module, create a Kconfig file and update the Makefile accordingly. Always run `make clean` before rebuilding to ensure a clean build process.$escape$,
  NULL,
  NULL,
