INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'fb5e2aba-fdb8-408e-9cc2-32dae05a2c4b',
  '00000000-0000-0000-0000-000000000001',
  $escape$linux_kernel Containers: Namespaces and cgroups$escape$,
  $escape$linux_kernel uses namespaces to isolate process views and cgroups to control resource allocation. Namespaces (ns) are file system objects that group resources, such as PID, network, and mount points. They are used to create a logical separation between processes. cgroups (control groups) are used to limit resource usage by processes. A process is associated with a cgroup, which defines the resources it can access. linux_kernel provides two types of cgroups: hierarchy and flat. Hierarchy cgroups are used for creating nested resource hierarchies, while flat cgroups are used for simple resource allocation. linux_kernel also provides several cgroup controllers for managing resources such as CPU, memory, and network I/O.$escape$,
  NULL,
  NULL,
